365: func (c *objectCache) shutdownWhenStopped(stopCh <-chan struct{}) {
366: 	<-stopCh
367: 
368: 	c.lock.Lock()
369: 	defer c.lock.Unlock()
370: 
371: 	c.stopped = true
372: 	for _, item := range c.items {
373: 		item.stop()
374: 	}
375: }
